import{_ as e,o,c as s,ag as l}from"./chunks/framework.gU7RhlGX.js";const b=JSON.parse('{"title":"baoyu-skills","description":"","frontmatter":{},"headers":[],"relativePath":"skills/写作类/baoyu-skills.md","filePath":"skills/写作类/baoyu-skills.md","lastUpdated":1776422487000}'),i={name:"skills/写作类/baoyu-skills.md"};function t(r,a,n,d,h,c){return o(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="baoyu-skills" tabindex="-1">baoyu-skills <a class="header-anchor" href="#baoyu-skills" aria-label="Permalink to &quot;baoyu-skills&quot;">​</a></h1><p><code>baoyu-skills</code> 是由知名技术专家宝玉老师自用并开源的一套 AI Agent Skill 集合。它深度集成了内容创作者从灵感、撰写、插图到发布的全流程工作流，旨在利用 AI 极大地提升内容生产效率。</p><hr><h2 id="🚀-快速开始" tabindex="-1">🚀 快速开始 <a class="header-anchor" href="#🚀-快速开始" aria-label="Permalink to &quot;🚀 快速开始&quot;">​</a></h2><h3 id="安装方式" tabindex="-1">安装方式 <a class="header-anchor" href="#安装方式" aria-label="Permalink to &quot;安装方式&quot;">​</a></h3><p>在你的项目终端中运行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jimliu/baoyu-skills</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者在支持辅助工具（如 Claude Code）的插件市场中搜索并安装。</p><hr><h2 id="核心功能模块" tabindex="-1">核心功能模块 <a class="header-anchor" href="#核心功能模块" aria-label="Permalink to &quot;核心功能模块&quot;">​</a></h2><h3 id="_1-视觉辅助与创作" tabindex="-1">1. 视觉辅助与创作 <a class="header-anchor" href="#_1-视觉辅助与创作" aria-label="Permalink to &quot;1. 视觉辅助与创作&quot;">​</a></h3><ul><li><strong><code>baoyu-cover-image</code></strong>：自动化生成文章封面图，支持 10 种色盘、7 种渲染风格及多种尺寸比例。</li><li><strong><code>baoyu-article-illustrator</code></strong>：智能分析文章结构，根据内容自动生成具有高度相关性的插图。</li><li><strong><code>baoyu-infographic</code></strong>：将复杂的文本内容转换为精美的信息图，内置 20 种布局和 17 种视觉风格。</li><li><strong><code>baoyu-xhs-images</code></strong>：专为小红书设计的配图工具，可按风格和布局系统生成系列组图。</li><li><strong><code>baoyu-slide-deck</code></strong>：根据内容快速生成 PPT 演示文稿的大纲及幻灯片素材。</li></ul><h3 id="_2-内容优化与格式化" tabindex="-1">2. 内容优化与格式化 <a class="header-anchor" href="#_2-内容优化与格式化" aria-label="Permalink to &quot;2. 内容优化与格式化&quot;">​</a></h3><ul><li><strong><code>baoyu-format-markdown</code></strong>：深度优化 Markdown 文档，包括公式化的标题建议、元数据 (frontmatter) 生成。</li><li><strong><code>baoyu-translate</code></strong>：具备工作流机制的高质量翻译，支持多种触发模式。</li><li><strong><code>baoyu-markdown-to-html</code></strong>：高度可定制的 Markdown 转 HTML 工具，支持自定义字体、颜色和代码主题。</li></ul><h3 id="_3-一键分发与工具类" tabindex="-1">3. 一键分发与工具类 <a class="header-anchor" href="#_3-一键分发与工具类" aria-label="Permalink to &quot;3. 一键分发与工具类&quot;">​</a></h3><ul><li><strong><code>baoyu-post-to-wechat</code> &amp; <code>baoyu-post-to-weibo</code></strong>：支持将处理好的内容一键同步发布到微信公众号和微博。</li><li><strong><code>baoyu-compress-image</code></strong>：轻量级图片压缩工具，处理生成后的视觉素材。</li></ul><hr><h2 id="进阶玩法" tabindex="-1">进阶玩法 <a class="header-anchor" href="#进阶玩法" aria-label="Permalink to &quot;进阶玩法&quot;">​</a></h2><p>可以通过项目根目录或用户目录下的 <code>EXTEND.md</code> 文件来自定义 Skill 的默认行为、覆盖配置或定义个性化预设。</p><hr><p><strong>官方仓库</strong>：<a href="https://github.com/JimLiu/baoyu-skills" target="_blank" rel="noreferrer">JimLiu/baoyu-skills</a></p>',21)])])}const p=e(i,[["render",t]]);export{b as __pageData,p as default};
